def approve_user(user_id: str):
    """Endpoint for admin to approve a user via email link."""
    conn = DBConnector.get_dpa_connection()
    if not conn:
        raise HTTPException(status_code=503, detail="Database unavailable")
    try:
        with conn.cursor() as cur:
            cur.execute("SELECT is_active FROM users WHERE user_id = %s", (user_id,))
            user = cur.fetchone()
            if not user:
                raise HTTPException(status_code=404, detail="User not found")
            if user[0]:
                return {"message": f"User {user_id} is already active."}

            cur.execute("UPDATE users SET is_active = True WHERE user_id = %s", (user_id,))
        conn.commit()

        # You could redirect to the frontend login page instead of returning JSON
        return {"message": f"User {user_id} has been successfully approved and activated!"}
    finally:
        DBConnector.release_dpa_connection(conn)

