def download_report(path: str, _user=Depends(get_current_user)):
    """Download a generated report — path must be inside OUTPUT_DIR."""
    safe_root = pathlib.Path(OUTPUT_DIR).resolve()
    result_root = pathlib.Path(r"D:\Auto_detect\Result").resolve()
    requested = pathlib.Path(path).resolve()

    is_safe = requested.is_relative_to(safe_root) or requested.is_relative_to(result_root)

    if not is_safe:
        raise HTTPException(status_code=403, detail="Access denied")
    if not requested.exists():
        raise HTTPException(status_code=404, detail="File not found")
    return FileResponse(
        path=str(requested),
        filename=requested.name,
        media_type="application/vnd.openxmlformats-officedocument.presentationml.presentation",
    )

