        // Store only the user profile (not the token — it lives in the httpOnly cookie).
        setUser(data.user);
        onLoginSuccess(data.user);
      } else {
        setError(data.detail || 'Login failed');
      }
    } catch {
      setError('Connection error. Please check if the server is running.');
    } finally {
      setLoading(false);
    }
  }

